# LAYER GROUP / wms_layer_group / abstract-parent fixture. Exercises:
#   - flat `GROUP "Basis"` -> `/Basis`
#   - hierarchical `wms_layer_group "/Adresse/Bygning"` (wins over GROUP)
#   - advertise-only parent: STATUS OFF + wms_enable_request "!GetMap" emits
#     a metadata-only Layer (title/abstract/keywords/metadata_url) with
#     get_map denied so the WMS surface still carries the parent block.
MAP
  NAME "groups"
  TITLE "WMS Layer Grouping Coverage"

  LAYER
    NAME "Basis_kort_root"
    STATUS OFF
    TYPE POLYGON
    METADATA
      "wms_layer_group"        "/Basis"
      "wms_enable_request"     "GetCapabilities !GetMap"
      "wms_title"              "Basis kort"
      "wms_abstract"           "Foundation cartography group"
      "wms_keywordlist"        "basis, foundation"
      "wms_metadataurl_type"   "ISO19115:2003"
      "wms_metadataurl_format" "text/xml"
      "wms_metadataurl_href"   "https://example.org/md/basis.xml"
    END
  END

  LAYER
    NAME "basemap"
    TYPE POLYGON
    DATA "geom FROM basemap"
    GROUP "Basis"
  END

  LAYER
    NAME "bygning"
    TYPE POLYGON
    DATA "geom FROM bygning"
    GROUP "Ignored"
    METADATA
      "wms_layer_group" "/Adresse/Bygning"
    END
  END

  LAYER
    NAME "ungrouped"
    TYPE LINE
    DATA "geom FROM lines"
  END
END
